import{_ as t,o as a,c as n,ae as o}from"./chunks/framework.B6gjLfeO.js";const c=JSON.parse('{"title":"Manage Your Engagement Groups","description":"","frontmatter":{"title":"Manage Your Engagement Groups","slug":"manage-your-engagement-groups"},"headers":[],"relativePath":"marketer-hub/manage-your-engagement-groups.md","filePath":"marketer-hub/manage-your-engagement-groups.md"}'),r={name:"marketer-hub/manage-your-engagement-groups.md"};function d(s,e,i,l,g,u){return a(),n("div",null,[...e[0]||(e[0]=[o('<h2 id="view-your-engagement-groups" tabindex="-1">View Your Engagement Groups <a class="header-anchor" href="#view-your-engagement-groups" aria-label="Permalink to &quot;View Your Engagement Groups&quot;">​</a></h2><p>Once you&#39;ve created an engagement group, you can view it in the <strong>Engagement Manager</strong> table.</p><p>The <strong>Engagement Manager</strong> table includes:</p><table tabindex="0"><thead><tr><th>Column Name</th><th>Description</th><th>Interactions</th></tr></thead><tbody><tr><td>Created</td><td>Date that the engagement group was created.</td><td>Sort column by name in first-to -last or last-to-first order. Default sort shows most recently created segments at top of table (last-to-first order)</td></tr><tr><td>Engagement Group Name</td><td>User defined engagement group name.</td><td>Sort in alphabetical ascending or descending order. Click <strong>Engagement Name</strong> to open the builder step-by-step process and edit the settings behind an engagement group.</td></tr><tr><td>More Info</td><td>This summary unit will contain a free text description entered by the user and a summary of settings taken from the audience rules. This is effectively the same unit of information that appears at the end of the step-by-step user flow.</td><td>Click on to show more information.</td></tr><tr><td>Update Frequency</td><td>Frequency of auto-updates and last update date.</td><td></td></tr><tr><td>Collaborators</td><td>All third parties associated with this audience segment; as indicated by agency IDs associated with the audience segment. This will be empty if the segment was created by the customer. It will show one agency name if created by an agency.</td><td></td></tr><tr><td>Status</td><td>Whether the audience segment is set to auto-fresh or not. Can be either “Active” or “Stopped”.</td><td>Sort column in alphabetical ascending or descending order.</td></tr><tr><td>Action</td><td>Access the &quot;CRUD&quot; menu via the ellipsis.</td><td><strong>Download Latest Batch</strong>: This will download the latest batch from the Engagement Group (Latest days worth, or weeks depending on the time frame) <strong>See Files to Download</strong>: This will take them to a Downloads page where users can see all files associated to the audience segment (including expired files) <strong>Edit</strong>: Access the step-by-step builder. <strong>Duplicate</strong>: Copies the audience segment rule to a new row without carrying over any exportable data (e.g. CSVs). User will need to re-launch the engagement group to generate any CSV. <strong>Stop Engagement Group</strong>: Turns off auto-fresh OR if group is already stopped, <strong>Resume Engagement Group</strong>. <strong>Delete</strong>: Removes engagement group and associated data.</td></tr></tbody></table><h2 id="download-an-engagement-group" tabindex="-1">Download an Engagement Group <a class="header-anchor" href="#download-an-engagement-group" aria-label="Permalink to &quot;Download an Engagement Group&quot;">​</a></h2><p>To view your available downloads for each engagement group, click on the Action ellipsis in the far right column.</p><p><strong>Download Latest Batch</strong></p><p>Download all available files from the latest batch. For example, if this is a daily updated engagement group, the latest days files would be downloaded. If this was weekly, the latest weeks files would be downloaded. There may be multiple files that are downloaded when this occurs.</p><p><strong>See Files to Download</strong></p><p>If selected, you are taken to a dedicated “Downloads” page where you can view all the files associated with the engagement group (including expired files). On this page, you can also select the files you wish to download.</p><p>The <strong>Downloads</strong> table includes:</p><table tabindex="0"><thead><tr><th>Column Name</th><th>Description</th><th>Actions</th></tr></thead><tbody><tr><td>Data Date</td><td>The calendar date the engagement group data was created.</td><td>Sort column in chronological ascending or descending order.</td></tr><tr><td>File Name</td><td>The name of the CSV file as provided by Branch.</td><td>Sort column in alphabetical ascending or descending order.</td></tr><tr><td>Last Updated</td><td>The calendar date and time the batch was last updated.</td><td>Sort column in chronological ascending or descending order.</td></tr><tr><td>Reach</td><td>The first number indicates reach in this file; bolded number indicates the total reach of the engagement group.</td><td></td></tr><tr><td>File Size</td><td>The total size of the file.</td><td></td></tr><tr><td>Status</td><td>The current number of days until the file expires or has already expired.</td><td>Sort column in chronological ascending or descending order.</td></tr><tr><td>Action</td><td>Download the respective file.</td><td></td></tr></tbody></table><div class="tip custom-block"><p class="custom-block-title">Things to Keep In Mind</p><ul><li>Engagement groups are run every 24hrs at 8pm PST. Depending on when you create the engagement group, exports may take up to 24hrs to be available for download.</li><li>Exports are CSV files.</li><li>Prepares one file for Android device IDs (GAID) and one file for iOS device ID (IDFA).</li><li>Downloads are accessible for 30 days. At 30 days, we purge the files, better enabling compliance with GDPR. The download table includes a count down to the expiry of a downloadable file (see text under the download link). Previously expired files are listed without an accessible download link.</li><li>Files are lists of device IDs with no other data.</li></ul></div><h2 id="modify-an-engagement-group" tabindex="-1">Modify an Engagement Group <a class="header-anchor" href="#modify-an-engagement-group" aria-label="Permalink to &quot;Modify an Engagement Group&quot;">​</a></h2><p>To modify an engagement group, click on the Action ellipsis in the far right column.</p><p>The following actions are available to modify an engagement group:</p><ul><li><strong>Edit</strong> - walks you through the engagement group creation wizard again.</li><li><strong>Duplicate</strong> - Copies the audience segment rule to a new row without carrying over any exportable data (e.g. CSVs).</li><li><strong>Stop/Resume Engagement Group</strong> - Turns off auto-fresh OR if group is already stopped,<br> resumes said group.</li><li><strong>Delete</strong> - Removes engagement group and associated data</li></ul>',17)])])}const p=t(r,[["render",d]]);export{c as __pageData,p as default};
